  ('pukao-6e11b43e-moex-00170', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-113-d1a761c9', 'sub-pukao-6e11b43e-02', NULL, 'single_choice', '關於地方制度法制定自治法規之規定，下列何者正確？', '["自治法規、委辦規則依規定應經其他機關核定者，至遲應於核定文送達各該地方行政機關15日內 公布或發布", "自治法規、委辦規則須經上級政府或委辦機關核定者，核定機關至遲應於2個月內為核定與否之決定", "自治條例經地方立法機關議決後，函送各該地方行政機關，地方行政機關收到後，至遲應於20日 內公布", "地方立法機關得訂定自律規則，並報各該上級政府備查"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:31+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "403", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
