  ('pukao-6e11b43e-moex-00176', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-113-d1a761c9', 'sub-pukao-6e11b43e-02', NULL, 'single_choice', '關於行政契約與行政處分之敘述，下列何者錯誤？', '["兩者同屬行政機關對個別事件所為具有對外效力之行政行為", "行政契約之一部無效者，原則上其他部分仍為有效；行政處分一部分無效者，原則上全部無效", "除法令有特別規定者外，行政機關作成行政處分有形式選擇自由時，得締結行政契約以替代行政處分", "行政契約之締結，原則上應以書面為之；行政處分原則上得以書面、言詞或其他方式為之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:31+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "403", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
